<?php
namespace App\Controllers; use App\Core\{Controller,View}; use App\Models\Product; use App\Services\SettingsService; use App\Services\Affiliate\{FanzaService,SokmilService,DugaService}; use function App\Core\{flash,redirect,verify_csrf}; final class ProductController extends Controller{private function svc(string $n){return match($n){'sokmil'=>new SokmilService(),'duga'=>new DugaService(),default=>new FanzaService()};} public function index():string{$this->requireAuth();return View::render('products/index',['products'=>Product::all(),'results'=>$_SESSION['search_results']??[]]);} public function search():string{$this->requireAuth();verify_csrf();$service=$_POST['service']??'fanza';$keyword=trim($_POST['keyword']??'');$settings=new SettingsService();$_SESSION['search_results']=$this->svc($service)->search($keyword,$settings->apiCredentials($service));flash('success','商品検索が完了しました。必要な商品を保存してください。');redirect('/products');} public function save():string{$this->requireAuth();verify_csrf();$idx=(int)($_POST['index']??-1);$rows=$_SESSION['search_results']??[];if(isset($rows[$idx])){Product::upsert($rows[$idx]);flash('success','商品を保存しました。');}redirect('/products');}}
